export const CARDS_COMMON_VOCAB = [
  { id: 776, category: "anzen", source: "vocab-lifeline", furi: "けつろ", jp: "結露", romaji: "ketsuro", id_text: "Kondensasi / embun", desc: "Air mengembun pada permukaan pipa dingin karena suhu lebih rendah dari titik embun udara.", _origIndex: 762 },
  { id: 778, category: "anzen", source: "vocab-lifeline", furi: "すいぶん", jp: "水分", romaji: "suibun", id_text: "Kandungan air / kelembapan", desc: "Jika 真空引き tidak tuntas → 水分が残る → pipa refrigeran rusak dari dalam. Di proyek: wajib vakum hingga tuntas. Mandor:「真空引きをしっかりやって」(lakukan pemvakuman dengan tuntas).", _origIndex: 764 },
  { id: 779, category: "anzen", source: "vocab-lifeline", furi: "こしょう", jp: "故障", romaji: "koshou", id_text: "Kerusakan / gangguan", desc: "Kegagalan fungsi peralatan. Refrigeran yang lembab → 内部故障. Di proyek: pemvakuman yang tidak sempurna menyebabkan kerusakan. Mandor:「故障を防ぐために真空引きを確実に」(vakum tuntas untuk mencegah kerusakan).", _origIndex: 765 },
  { id: 780, category: "anzen", source: "vocab-lifeline", furi: "もれ", jp: "漏れ", romaji: "more", id_text: "Kebocoran", desc: "Cairan atau gas yang keluar dari tempat yang seharusnya tertutup.", _origIndex: 766 },
  { id: 783, category: "anzen", source: "vocab-lifeline", furi: "ふちゃく", jp: "付着", romaji: "fuchaku", id_text: "Menempel / melekat", desc: "油が付着する = minyak menempel. Pada 冷媒管接続部 → シール性が低下する. Di proyek: bersihkan bagian sambungan sebelum memasang. Mandor:「接続部の油を拭き取ってから取り付けて」(bersihkan minyak dulu).", _origIndex: 769 },
  { id: 784, category: "anzen", source: "vocab-lifeline", furi: "しんにゅう", jp: "侵入", romaji: "shinnyuu", id_text: "Masuk / infiltrasi", desc: "水が侵入する = air masuk ke dalam. Di proyek: ujung konduit wajib ditutup dengan sealant. Mandor:「管端にシーリング材を充填して水の侵入を防いで」(isi sealant di ujung konduit).", _origIndex: 770 },
  { id: 785, category: "anzen", source: "vocab-lifeline", furi: "たわみはっせい", jp: "たわみ発生", romaji: "tawami hassei", id_text: "Timbulnya lendutan", desc: "Ketika jarak saddle terlalu lebar, pipa melengkung ke bawah.", _origIndex: 771 },
  { id: 788, category: "anzen", source: "vocab-lifeline", furi: "すきま", jp: "隙間", romaji: "sukima", id_text: "Celah / gap", desc: "Celah pada material insulasi tempat panas bisa bocor keluar → ヒートロス.", _origIndex: 774 },
  { id: 792, category: "sekou", source: "vocab-lifeline", furi: "あんぜんかくにん", jp: "安全確認", romaji: "anzen kakunin", id_text: "Pemeriksaan keamanan", desc: "Langkah verifikasi bahwa kondisi sudah aman sebelum/sesudah pekerjaan.", _origIndex: 778 },
  { id: 793, category: "sekou", source: "vocab-lifeline", furi: "かくにん", jp: "確認", romaji: "kakunin", id_text: "Konfirmasi / pengecekan", desc: "Memastikan suatu hal sudah benar. 施工前に確認する = periksa sebelum mulai konstruksi.", _origIndex: 779 },
  { id: 795, category: "anzen", source: "vocab-lifeline", furi: "ぼうし", jp: "防止", romaji: "boushi", id_text: "Pencegahan", desc: "凍結防止、感電防止、結露防止 — istilah pencegahan sering muncul di soal ujian.", _origIndex: 781 },
  { id: 796, category: "anzen", source: "vocab-lifeline", furi: "こうしょさぎょう", jp: "高所作業", romaji: "kousho sagyou", id_text: "Pekerjaan di ketinggian", desc: "Pekerjaan di atas 2m dari lantai/tanah. Bahaya utama: 落下 (jatuh) dan 感電 (kesetrum).", _origIndex: 782 },
  { id: 797, category: "anzen", source: "vocab-lifeline", furi: "らっか", jp: "落下", romaji: "rakka", id_text: "Jatuh", desc: "Bahaya utama pekerjaan di ketinggian. Wajib pakai harness & jaring pengaman.", _origIndex: 783 },
  { id: 798, category: "anzen", source: "vocab-lifeline", furi: "そうおん", jp: "騒音", romaji: "souon", id_text: "Kebisingan", desc: "Bahaya yang juga perlu diperhatikan, tapi bukan bahaya utama di 高所溶接作業.", _origIndex: 784 },
  { id: 799, category: "anzen", source: "vocab-lifeline", furi: "きけん", jp: "危険", romaji: "kiken", id_text: "Bahaya", desc: "危険予知活動 (KY活動) = kegiatan identifikasi bahaya sebelum bekerja.", _origIndex: 785 },
  { id: 800, category: "anzen", source: "vocab-lifeline", furi: "あーす", jp: "アース", romaji: "aasu", id_text: "Grounding / pentanahan", desc: "Menghubungkan peralatan listrik ke tanah. Tujuan utama: 感電防止 (mencegah sengatan listrik).", _origIndex: 786 },
  { id: 801, category: "anzen", source: "vocab-lifeline", furi: "しょち", jp: "処置", romaji: "shochi", id_text: "Tindakan penanganan", desc: "Langkah yang diambil untuk mengatasi/mencegah masalah. 水侵入を防ぐための処置.", _origIndex: 787 },
  { id: 805, category: "sekou", source: "vocab-lifeline", furi: "ほおん", jp: "保温", romaji: "hoon", id_text: "Retensi panas / insulasi panas", desc: "Menjaga suhu pipa/peralatan panas agar tidak dingin. 保温 ≠ 断熱 (断熱 lebih umum).", _origIndex: 790 },
  { id: 806, category: "sekou", source: "vocab-lifeline", furi: "ようせつ", jp: "溶接", romaji: "yousetsu", id_text: "Pengelasan", desc: "Menyambung logam dengan panas tinggi. Setelah selesai → wajib 漏れ検査.", _origIndex: 791 },
  { id: 808, category: "sekou", source: "vocab-lifeline", furi: "じゅうてん", jp: "充填", romaji: "juuten", id_text: "Pengisian / penyumbatan", desc: "管端にシーリング材を充填する = isi sealant di ujung pipa konduit. Di proyek: mencegah air masuk ke dalam konduit. Mandor:「管端にシーリング材を充填して」(isi sealant di ujung pipa).", _origIndex: 793 },
  { id: 809, category: "sekou", source: "vocab-lifeline", furi: "はっせい", jp: "発生", romaji: "hassei", id_text: "Timbul / terjadi", desc: "錆が発生した = karat timbul. 異音が発生する = suara abnormal terjadi. Di proyek: karat di dalam pipa harus dibersihkan sebelum konstruksi. Mandor:「錆が発生したら施工前に洗浄して」(cuci dulu jika ada karat).", _origIndex: 794 },
  { id: 813, category: "sekou", source: "vocab-lifeline", furi: "ぼうすいかばー", jp: "防水カバー", romaji: "bousui kabaa", id_text: "Penutup anti-air", desc: "Penutup tahan air untuk melindungi insulasi pipa di luar ruangan dari hujan.", _origIndex: 798 },
  { id: 821, category: "career", source: "vocab-lifeline", furi: "ふじゅうぶん", jp: "不十分", romaji: "fujuubun", id_text: "Tidak mencukupi / kurang", desc: "真空引きを不十分に行った場合 = jika pemvakuman dilakukan secara tidak mencukupi.", _origIndex: 805 },
  { id: 822, category: "career", source: "vocab-lifeline", furi: "ふそく", jp: "不足", romaji: "fusoku", id_text: "Kekurangan / kurang", desc: "勾配不足が原因で起こる問題 = masalah yang terjadi akibat kemiringan pipa kurang.", _origIndex: 806 },
  { id: 823, category: "career", source: "vocab-lifeline", furi: "あんてい", jp: "安定", romaji: "antei", id_text: "Stabil", desc: "圧力試験の結果が安定しない場合の原因 = penyebab hasil uji tekanan tidak stabil.", _origIndex: 807 },
  { id: 824, category: "career", source: "vocab-lifeline", furi: "げんいん", jp: "原因", romaji: "gen'in", id_text: "Penyebab", desc: "Faktor yang menyebabkan masalah. 圧力不安定の原因 = 漏れの有無 (ada tidaknya kebocoran).", _origIndex: 808 },
  { id: 827, category: "career", source: "vocab-lifeline", furi: "ないめん", jp: "内面", romaji: "naimen", id_text: "Permukaan dalam", desc: "配管の内面に錆が発生した場合 = ketika karat muncul di permukaan dalam pipa.", _origIndex: 811 },
  { id: 828, category: "career", source: "vocab-lifeline", furi: "ないぶ", jp: "内部", romaji: "naibu", id_text: "Bagian dalam / interior", desc: "内部に水分が残り故障する = kelembapan tersisa di bagian dalam → menyebabkan kerusakan.", _origIndex: 812 },
  { id: 829, category: "career", source: "vocab-lifeline", furi: "ずめん", jp: "図面", romaji: "zumen", id_text: "Gambar teknik / denah", desc: "埋設配管の位置を将来確認するために、施工時に図面に記録する. Di proyek: gambar teknik adalah acuan utama. Mandor:「埋設配管の位置を必ず図面に記録して」(catat posisi pipa terpendam di gambar).", _origIndex: 813 },
  { id: 831, category: "career", source: "vocab-lifeline", furi: "おんど", jp: "温度", romaji: "ondo", id_text: "Suhu / temperatur", desc: "Besaran fisik panas suatu benda. Muncul sebagai pengecoh: '温度が一定になる', '温度の変化'.", _origIndex: 815 },
  { id: 832, category: "career", source: "vocab-lifeline", furi: "うむ", jp: "有無", romaji: "umu", id_text: "Ada tidaknya / keberadaan", desc: "漏れの有無を確認する = periksa ada tidaknya kebocoran. Penyebab hasil uji tekanan tidak stabil.", _origIndex: 816 },
  { id: 836, category: "career", source: "vocab-lifeline", furi: "じゅうりょう", jp: "重量", romaji: "juuryou", id_text: "Berat / massa", desc: "Beban fisik suatu objek. Sering muncul sebagai pilihan pengecoh: '重量が増える' (berat bertambah).", _origIndex: 820 },
  { id: 838, category: "anzen", source: "vocab-lifeline", furi: "ていか", jp: "低下", romaji: "teika", id_text: "Penurunan / penurun fungsi", desc: "シール性が低下する = kemampuan sealing menurun. Terjadi bila 冷媒管接続部 terkena 油.", _origIndex: 822 },
  { id: 839, category: "career", source: "vocab-lifeline", furi: "いち", jp: "位置", romaji: "ichi", id_text: "Posisi / lokasi", desc: "埋設配管の位置を図面に記録する = catat posisi pipa terpendam di gambar teknik agar bisa dilacak kelak.", _origIndex: 823 },
  { id: 840, category: "anzen", source: "vocab-lifeline", furi: "はそん", jp: "破損", romaji: "hason", id_text: "Kerusakan / pecah", desc: "圧力計の破損 = manometer rusak. Muncul sebagai pengecoh penyebab 異音 saat katup dibuka.", _origIndex: 824 },
  { id: 844, category: "career", source: "vocab-lifeline", furi: "おくがい", jp: "屋外", romaji: "okugai", id_text: "Luar ruangan / outdoor", desc: "Di luar gedung. 屋外配線 = kabel luar ruangan（rentan UV）. 屋外で配管保温を行う場合 = saat insulasi pipa di luar ruangan → wajib tambah 防水カバー.", _origIndex: 828 },
  { id: 845, category: "career", source: "vocab-lifeline", furi: "しゅるい", jp: "種類", romaji: "shurui", id_text: "Jenis / tipe", desc: "冷媒の種類 = jenis refrigeran. Muncul sebagai pengecoh di Q4. Penyebab 結露 多発 bukan jenis refrigeran, melainkan ketipisan 断熱材.", _origIndex: 829 },
  { id: 846, category: "career", source: "vocab-lifeline", furi: "もくてき", jp: "目的", romaji: "mokuteki", id_text: "Tujuan / maksud", desc: "アースを取る主な目的 = tujuan utama pemasangan grounding. Jawaban: 感電防止 (mencegah sengatan listrik).", _origIndex: 830 },
  { id: 847, category: "anzen", source: "vocab-lifeline", furi: "じょうしょう", jp: "上昇", romaji: "joushou", id_text: "Kenaikan / peningkatan", desc: "温度上昇防止 = mencegah kenaikan suhu. Muncul sebagai pengecoh di Q13 (tujuan アース). Tujuan アース bukan mencegah 温度上昇, melainkan 感電防止.", _origIndex: 831 },
  { id: 848, category: "sekou", source: "vocab-lifeline", furi: "そくてい", jp: "測定", romaji: "sokutei", id_text: "Pengukuran / pengujian", desc: "騒音測定 = pengukuran kebisingan. Muncul sebagai pengecoh di Q8 (安全確認 gas). Jawaban benar Q8 adalah ガス漏れ試験, bukan 騒音測定.", _origIndex: 832 },
  { id: 849, category: "career", source: "vocab-lifeline", furi: "けっか", jp: "結果", romaji: "kekka", id_text: "Hasil / hasil akhir", desc: "圧力試験の結果が安定しない場合 = jika hasil uji tekanan tidak stabil → kemungkinan ada 漏れ (kebocoran).", _origIndex: 833 },
  { id: 850, category: "career", source: "vocab-lifeline", furi: "へんか", jp: "変化", romaji: "henka", id_text: "Perubahan", desc: "温度の変化 = perubahan suhu（pengecoh Q6）. 色の変化 = perubahan warna（pengecoh Q19）. Kedua-duanya bukan penyebab utama dalam soal terkait.", _origIndex: 834 },
  { id: 852, category: "career", source: "vocab-lifeline", furi: "もんだい", jp: "問題", romaji: "mondai", id_text: "Masalah / persoalan", desc: "勾配不足が原因で起こる問題 = masalah yang timbul akibat kemiringan pipa kurang. Kunci: 流れが悪くなる (aliran memburuk).", _origIndex: 836 },
  { id: 856, category: "career", source: "vocab-lifeline", furi: "いってい", jp: "一定", romaji: "ittei", id_text: "Tetap / konstan", desc: "温度が一定になる = suhu menjadi konstan. Pengecoh Q2 — bukan efek dari 真空引き yang tidak tuntas. Efek nyatanya: 水分が残り故障する.", _origIndex: 840 },
  { id: 857, category: "sekou", source: "vocab-lifeline", furi: "とりつけ", jp: "取り付け", romaji: "toritsuke", id_text: "Pemasangan / instalasi", desc: "防水カバー取り付け = pemasangan penutup anti-air. Jawaban benar Q12 — pekerjaan tambahan saat insulasi pipa di luar ruangan.", _origIndex: 841 },
  { id: 858, category: "sekou", source: "vocab-lifeline", furi: "こうかん", jp: "交換", romaji: "koukan", id_text: "Penggantian / tukar", desc: "圧力計交換 = mengganti manometer. Pengecoh Q12 — bukan pekerjaan tambahan yang dibutuhkan saat insulasi pipa luar ruangan.", _origIndex: 842 },
  { id: 859, category: "sekou", source: "vocab-lifeline", furi: "とそう", jp: "塗装", romaji: "tosou", id_text: "Pengecatan / pelapisan", desc: "色塗装 = pengecatan warna. Pengecoh Q12 — bukan tindakan tambahan standar untuk insulasi pipa di luar ruangan.", _origIndex: 843 },
  { id: 863, category: "career", source: "vocab-lifeline", furi: "ながさ", jp: "長さ", romaji: "nagasa", id_text: "Panjang / panjangnya", desc: "長さをそろえる = menyamakan panjang kabel. Pengecoh Q18 — saat memasukkan banyak kabel dalam konduit, yang penting bukan panjang tapi agar 熱がこもらない (panas tidak terperangkap).", _origIndex: 847 },
  { id: 865, category: "career", source: "vocab-lifeline", furi: "あさい", jp: "浅い", romaji: "asai", id_text: "Dangkal", desc: "配管を浅く埋める = kubur pipa dangkal-dangkal. Pengecoh Q1 — pipa bawah tanah yang dangkal justru lebih rentan membeku. Harus pakai 保温材＋電熱線.", _origIndex: 849 },
  { id: 867, category: "anzen", source: "vocab-lifeline", furi: "ちゅうい", jp: "注意", romaji: "chuui", id_text: "Perhatian / kewaspadaan", desc: "特に注意するべき危険 = bahaya yang perlu diwaspadai khususnya. Muncul di Q5 (高所溶接). 注意する = memperhatikan / waspada.", _origIndex: 851 },
  { id: 870, category: "sekou", source: "vocab-lifeline", furi: "ひやす", jp: "冷やす", romaji: "hiyasu", id_text: "Mendinginkan / mengompres", desc: "コードを水で冷やす = dinginkan kabel dengan air. Pengecoh Q9 — JANGAN lakukan ini! Kabel panas → segera 使用を中止する. Air bisa menyebabkan korsleting.", _origIndex: 854 },
  { id: 871, category: "career", source: "vocab-lifeline", furi: "つよい", jp: "強い", romaji: "tsuyoi", id_text: "Kuat / keras", desc: "電源を強くする = perkuat/naikkan daya listrik. Pengecoh Q9 — JANGAN dilakukan saat kabel panas. Justru memperburuk kondisi → kebakaran. Solusi: 使用中止.", _origIndex: 855 },
  { id: 876, category: "career", source: "vocab-lifeline", furi: "ばあい", jp: "場合", romaji: "baai", id_text: "Dalam kasus / apabila", desc: "〜の場合（ばあい）= dalam kasus〜 / apabila〜. Muncul di hampir semua soal sebagai frasa syarat: 結露が多発する場合、コードが熱くなる場合, dll.", _origIndex: 860 },
  { id: 877, category: "sekou", source: "vocab-lifeline", furi: "まく", jp: "巻く", romaji: "maku", id_text: "Membelit / melilit", desc: "絶縁テープで巻く = balut dengan selotip insulasi. Pengecoh Q3 — selotip insulasi (絶縁テープ) bukan untuk waterproofing. Yang benar: シーリング材を充填する.", _origIndex: 861 },
  { id: 878, category: "career", source: "vocab-lifeline", furi: "ふとい", jp: "太い", romaji: "futoi", id_text: "Tebal / gemuk (kabel)", desc: "電線を太くする = ganti kabel lebih tebal. Pengecoh Q3 — ketebalan kabel tidak mencegah air masuk ke konduit. Yang benar: 管端にシーリング材を充填する.", _origIndex: 862 },
  { id: 879, category: "sekou", source: "vocab-lifeline", furi: "おおう", jp: "覆う", romaji: "oou", id_text: "Menutup / menyelimuti", desc: "黒色テープで覆う = tutup dengan selotip hitam. Pengecoh Q7. 耐候性カバーで覆う = tutup dengan pelindung tahan cuaca → metode benar pencegahan UV.", _origIndex: 863 },
  { id: 881, category: "sekou", source: "vocab-lifeline", furi: "きる", jp: "切る", romaji: "kiru", id_text: "Memotong", desc: "電線を短く切る = potong kabel lebih pendek. Pengecoh Q7. Juga terkait 使用を中止する (hentikan, bukan potong) pada Q9.", _origIndex: 865 },
  { id: 882, category: "career", source: "vocab-lifeline", furi: "よぶ", jp: "呼ぶ", romaji: "yobu", id_text: "Menyebut / memanggil", desc: "何と呼びますか = disebut apa? Pola pertanyaan nama/istilah. Muncul di Q10: 断熱材の隙間から熱が漏れる現象は何と呼びますか → ヒートロス.", _origIndex: 866 },
  { id: 883, category: "career", source: "vocab-lifeline", furi: "おもな", jp: "主な", romaji: "omona", id_text: "Utama / terutama", desc: "主な目的（おもなもくてき）= tujuan utama. Muncul di Q13: アースを取る主な目的は何ですか → 感電防止. 主に = terutama, 主な = yang utama.", _origIndex: 867 },
  { id: 886, category: "sekou", source: "vocab-lifeline", furi: "ぬる", jp: "塗る", romaji: "nuru", id_text: "Mengecat / melapisi", desc: "色を塗る = mengecat dengan warna. Pengecoh Q15 — mengecat pipa bukan cara untuk menandai posisi pipa bawah tanah. Yang benar: 図面に記録する.", _origIndex: 870 },
  { id: 887, category: "sekou", source: "vocab-lifeline", furi: "つける", jp: "付ける", romaji: "tsukeru", id_text: "Memasang / menempelkan", desc: "圧力計を付ける = pasang manometer. Pengecoh Q15 — memasang manometer bukan cara untuk menandai posisi pipa bawah tanah. Yang benar: 図面に記録する.", _origIndex: 871 },
  { id: 891, category: "sekou", source: "vocab-lifeline", furi: "せこうまえ", jp: "施工前", romaji: "sekou mae", id_text: "Sebelum konstruksi", desc: "施工前に何を行いますか = apa yang dilakukan sebelum konstruksi? Konteks Q11: jika pipa berkarat → 施工前に洗浄と防錆処理を行う. 施工前 = sebelum mulai pengerjaan konstruksi.", _origIndex: 875 },
  { id: 892, category: "career", source: "vocab-lifeline", furi: "ちゅういてん", jp: "注意点", romaji: "chuuiten", id_text: "Poin perhatian / hal yang perlu diperhatikan", desc: "注意点は何ですか = apa yang perlu diperhatikan? Konteks Q18: 電線を複数束ねて配管に通す場合の注意点 → 熱がこもらないようにする. Beda dari 注意（ちゅうい）= peringatan umum.", _origIndex: 876 },
  { id: 893, category: "career", source: "vocab-lifeline", furi: "かならず", jp: "必ず", romaji: "kanarazu", id_text: "Wajib / pasti / selalu", desc: "必ず行うべき = yang wajib dilakukan. Kata kunci soal prosedur wajib. Muncul di Q8 (ガス配管接続→ガス漏れ試験必ず) dan Q16 (溶接作業後→漏れ検査必ず). 必ず = tidak boleh dilewati.", _origIndex: 877 },
  { id: 894, category: "career", source: "vocab-lifeline", furi: "まず", jp: "まず", romaji: "mazu", id_text: "Pertama-tama / langkah pertama", desc: "まず行うべきことは何ですか = apa yang pertama harus dilakukan? Muncul di Q4 (まず確認すべき点 → 断熱材の厚さ) dan Q9 (まず行うべきこと → 使用を中止する). まず = urutan prioritas utama.", _origIndex: 878 },
  { id: 895, category: "career", source: "vocab-lifeline", furi: "とくに", jp: "特に", romaji: "tokuni", id_text: "Khususnya / terutama", desc: "特に注意するべき危険は何ですか = bahaya apa yang khususnya perlu diwaspadai? Muncul di Q5 (高所溶接 → 特に注意 = 落下). 特に = kata penekanan untuk hal paling penting/prioritas.", _origIndex: 879 },
  { id: 897, category: "career", source: "vocab-lifeline", furi: "ふせぐ", jp: "防ぐ", romaji: "fusegu", id_text: "Mencegah / melindungi dari", desc: "〜を防ぐ = mencegah〜. Muncul di Q3: 電線管に水が侵入するのを防ぐための処置, dan Q7: 紫外線劣化を防ぐ方法. 防止（ぼうし）= pencegahan (kata benda); 防ぐ = mencegah (kata kerja).", _origIndex: 881 },
  { id: 898, category: "career", source: "vocab-lifeline", furi: "おこなう", jp: "行う", romaji: "okonau", id_text: "Melakukan / melaksanakan", desc: "〜を行う = melaksanakan〜. Kata kerja paling sering di soal ujian. 施工を行う = melaksanakan konstruksi, 検査を行う = melakukan inspeksi, 処置を行う = mengambil tindakan. Formal version of する.", _origIndex: 882 },
  { id: 899, category: "career", source: "vocab-lifeline", furi: "かんがえられる", jp: "考えられる", romaji: "kangaerareru", id_text: "Yang dapat diperkirakan / kemungkinan", desc: "考えられる原因 = penyebab yang mungkin / dapat diperkirakan. Muncul di Q6: 圧力試験の結果が安定しない場合、考えられる原因はどれですか → 漏れの有無. Bentuk potensial pasif dari 考える（かんがえる）.", _origIndex: 883 },
  { id: 900, category: "career", source: "vocab-lifeline", furi: "しようちゅう", jp: "使用中", romaji: "shiyouchuu", id_text: "Saat digunakan / sedang digunakan", desc: "使用中（しようちゅう）= sedang dipakai / dalam penggunaan. Konteks Q9: 電動工具使用中にコードが熱くなる場合 = saat power tool sedang digunakan dan kabelnya panas. 〜中 = sedang berlangsung.", _origIndex: 884 },
  { id: 901, category: "career", source: "vocab-lifeline", furi: "べき", jp: "べき", romaji: "beki", id_text: "Seharusnya / harus dilakukan", desc: "動詞 + べき = seharusnya melakukan〜 / wajib〜. Muncul di banyak soal: 必ず行うべき検査, まず行うべきこと, 注意するべき危険. 〜すべき = 〜するべき (harus/seharusnya). Kata kunci soal prosedur wajib.", _origIndex: 885 },
  { id: 902, category: "career", source: "vocab-lifeline", furi: "おこる", jp: "起こる", romaji: "okoru", id_text: "Terjadi / timbul", desc: "Kata kerja PALING SERING di soal — muncul di Q2,Q14,Q17,Q19,Q20 sebagai '何が起こりますか'. 起こる = terjadi (intransitif); 起こす = menyebabkan (transitif). Hafal polanya: 〜すると何が起こりますか = jika〜, apa yang terjadi?", _origIndex: 886 },
  { id: 903, category: "career", source: "vocab-lifeline", furi: "のこる", jp: "残る", romaji: "nokoru", id_text: "Tersisa / tertinggal", desc: "水分が残り故障する = kelembapan tersisa → menyebabkan kerusakan. Konteks Q2: pemvakuman tidak tuntas → 水分が残る (kelembapan tertinggal di dalam pipa refrigeran). 残る = tersisa; 残す = menyisakan (transitif).", _origIndex: 887 },
  { id: 904, category: "sekou", source: "vocab-lifeline", furi: "しけん", jp: "試験", romaji: "shiken", id_text: "Uji / pengujian (tekanan/teknis)", desc: "圧力試験（Q6）= uji tekanan. ガス漏れ試験（Q8）= uji kebocoran gas. 試験 = pengujian terhadap batas/standar teknis. Berbeda dari 検査（けんさ）= inspeksi kondisi visual/kebocoran pasca-konstruksi.", _origIndex: 888 },
  { id: 905, category: "sekou", source: "vocab-lifeline", furi: "けんさ", jp: "検査", romaji: "kensa", id_text: "Inspeksi / pemeriksaan", desc: "漏れ検査（Q16）= inspeksi kebocoran — WAJIB setelah pengelasan. 色検査 & 音検査 = pengecoh Q16. 検査 = pemeriksaan kondisi pasca-pekerjaan. Berbeda dari 試験（しけん）= pengujian teknis terhadap standar/tekanan.", _origIndex: 889 },
  { id: 906, category: "sekou", source: "vocab-lifeline", furi: "さぎょう", jp: "作業", romaji: "sagyou", id_text: "Pekerjaan / operasi kerja", desc: "高所作業（Q5）= pekerjaan di ketinggian. 溶接作業後（Q16）= setelah pekerjaan pengelasan. 作業中 = sedang bekerja. 作業員（さぎょういん）= pekerja/operator. Lebih spesifik dari 工事（pekerjaan konstruksi besar）.", _origIndex: 890 },
  { id: 907, category: "career", source: "vocab-lifeline", furi: "ほうほう", jp: "方法", romaji: "houhou", id_text: "Cara / metode", desc: "施工方法（Q1）= metode konstruksi. 防ぐ方法（Q7）= cara mencegah. 〜のための方法/〜する方法 = cara untuk〜. Sering menjadi kata kunci pertanyaan 'bagaimana caranya'. Beda dari 施工方法（metode khusus konstruksi）.", _origIndex: 891 },
  { id: 909, category: "anzen", source: "vocab-lifeline", furi: "あんぜん", jp: "安全", romaji: "anzen", id_text: "Aman / keselamatan", desc: "安全確認（Q8）= pemeriksaan keamanan. 安全管理 = manajemen K3. 安全第一 = safety first. 安全 = kondisi aman/safety. Kata dasar yang sering kombinasi: 安全確認、安全管理、安全帯（ハーネス）.", _origIndex: 893 },
  { id: 910, category: "sekou", source: "vocab-lifeline", furi: "せこう", jp: "施工", romaji: "sekou", id_text: "Pelaksanaan konstruksi", desc: "Kata dasar dari: 施工方法（cara konstruksi）, 施工前（sebelum konstruksi）, 施工時（saat konstruksi）, 追加施工（konstruksi tambahan）, 施工後（setelah konstruksi）. 施工する = melaksanakan konstruksi.", _origIndex: 894 },
  { id: 911, category: "sekou", source: "vocab-lifeline", furi: "とる", jp: "取る", romaji: "toru", id_text: "Mengambil / memasang / mendapatkan", desc: "アースを取る（Q13）= memasang grounding. 取り付け（とりつけ）= pemasangan（Q12）. 取る banyak makna kontekstual: mengambil, memasang, mendapatkan. Perhatikan bentuk: 取り付ける = memasang (lebih spesifik).", _origIndex: 895 },
  { id: 912, category: "career", source: "vocab-jac", furi: "せいり", jp: "整理", romaji: "seiri", id_text: "Pilah / sortir", desc: "整理 = menyortir/memilah barang. S pertama dari 5S. Di proyek: barang tidak perlu disingkirkan dari area kerja. Mandor:「いらないものは整理して」(pilah dan singkirkan yang tidak perlu).", _origIndex: 896 },
  { id: 913, category: "career", source: "vocab-jac", furi: "せいとん", jp: "整頓", romaji: "seiton", id_text: "Tata / rapikan", desc: "例: 工具を決めた場所に整頓する。→ Taruh alat di tempat yang sudah ditentukan.", _origIndex: 897 },
  { id: 914, category: "career", source: "vocab-jac", furi: "せいそう", jp: "清掃", romaji: "seisou", id_text: "Bersihkan / sapu", desc: "例: 毎日作業後に清掃する。→ Bersihkan area kerja setelah selesai setiap hari.", _origIndex: 898 },
  { id: 915, category: "career", source: "vocab-jac", furi: "せいけつ", jp: "清潔", romaji: "seiketsu", id_text: "Jaga kebersihan / higienis", desc: "例: 作業員詰め所を清潔に保つ。→ Jaga ruang pekerja tetap bersih dan sehat.", _origIndex: 899 },
  { id: 916, category: "career", source: "vocab-jac", furi: "しつけ", jp: "しつけ", romaji: "shitsuke", id_text: "Disiplin / kebiasaan baik", desc: "例: 5Sの5つ目はしつけ。→ Elemen ke-5 dari 5S = disiplin menjaga aturan.", _origIndex: 900 },
  { id: 917, category: "career", source: "vocab-jac", furi: "ちーむわーく", jp: "チームワーク", romaji: "chiimu waaku", id_text: "Kerja tim", desc: "例: 専門業者間のチームワークが大切。→ Kunci lancarnya konstruksi multi-kontraktor.", _origIndex: 901 },
  { id: 918, category: "career", source: "vocab-jac", furi: "ゆういせい", jp: "優位性", romaji: "yuuisei", id_text: "Keunggulan / superioritas posisi", desc: "例: 職場の優位性を利用したいじめ＝パワハラ。→ Memanfaatkan jabatan untuk menekan orang lain.", _origIndex: 902 },
  { id: 919, category: "career", source: "vocab-jac", furi: "くつう", jp: "苦痛", romaji: "kutsuu", id_text: "Penderitaan / tekanan", desc: "例: 精神的な苦痛を与える行為はパワハラ。→ Tindakan yang menyebabkan penderitaan mental = pelecehan.", _origIndex: 903 },
  { id: 920, category: "career", source: "vocab-jac", furi: "ろうどうしゃ", jp: "労働者", romaji: "roudousha", id_text: "Pekerja / tenaga kerja", desc: "例: 労働者の安全を守る法律＝労働安全衛生法。→ UU yang melindungi keselamatan pekerja.", _origIndex: 904 },
  { id: 921, category: "career", source: "vocab-jac", furi: "じぎょうぬし", jp: "事業主", romaji: "jigyounushi", id_text: "Pemberi kerja / majikan", desc: "例: 労災保険の保険料は事業主が払う。→ Premi asuransi kecelakaan kerja ditanggung majikan.", _origIndex: 905 },
  { id: 922, category: "career", source: "vocab-jac", furi: "ししつ", jp: "資質", romaji: "shishitsu", id_text: "Kualitas / kompetensi / mutu SDM", desc: "例: 建設業法の目的は業者の資質の向上。→ Tujuan UU Konstruksi = tingkatkan mutu pelaku usaha.", _origIndex: 906 },
  { id: 923, category: "career", source: "vocab-jac", furi: "はいざい", jp: "廃材", romaji: "haizai", id_text: "Material limbah / sisa bongkaran", desc: "例: 廃材の適切な処理は建設リサイクル法で定める。→ Penanganan limbah material diatur UU Daur Ulang Konstruksi.", _origIndex: 907 },
  { id: 924, category: "career", source: "vocab-jac", furi: "さいていげん", jp: "最低限", romaji: "saiteigen", id_text: "Minimum / batas paling rendah", desc: "例: 建築基準法は最低限のルールを定める。→ UU Standar Bangunan menetapkan aturan minimum.", _origIndex: 908 },
  { id: 925, category: "career", source: "vocab-jac", furi: "けいげん", jp: "軽減", romaji: "keigen", id_text: "Pengurangan / mitigasi", desc: "例: 消防法は火災の被害を軽減する目的。→ UU Pemadam bertujuan memitigasi kerugian kebakaran.", _origIndex: 909 },
  { id: 926, category: "career", source: "vocab-jac", furi: "あんか", jp: "安価", romaji: "anka", id_text: "Murah / terjangkau", desc: "例: 水道法は安価な水の供給を目指す。→ UU Air Bersih bertujuan menyediakan air dengan harga terjangkau.", _origIndex: 910 },
  { id: 927, category: "career", source: "vocab-jac", furi: "ぎのうこうしゅう", jp: "技能講習", romaji: "ginou koushu", id_text: "Pelatihan wajib sebelum operasikan mesin berat", desc: "例: 車両系建設機械3t以上は技能講習が必要。→ Alat berat ≥3t wajib ikut pelatihan keterampilan.", _origIndex: 911 },
  { id: 928, category: "career", source: "vocab-jac", furi: "とくべつきょういく", jp: "特別教育", romaji: "tokubetsu kyouiku", id_text: "Pendidikan khusus (wajib K3)", desc: "例: アーク溶接は特別教育が必要。→ Las busur wajib ikut pendidikan khusus K3.", _origIndex: 912 },
  { id: 929, category: "career", source: "vocab-jac", furi: "めんきょ", jp: "免許", romaji: "menkyo", id_text: "Lisensi / SIM / izin resmi negara", desc: "免許 = lisensi resmi dari negara. Las gas, crane, dan listrik memerlukan lisensi. Di proyek: pekerja tanpa lisensi tidak boleh mengoperasikan alat. Mandor:「免許を持っているか確認して」(pastikan punya lisensi).", _origIndex: 913 },
  { id: 930, category: "sekou", source: "vocab-jac", furi: "じゅんびこうじ", jp: "準備工事", romaji: "junbi kouji", id_text: "Pekerjaan persiapan", desc: "例: 着工前に準備工事を行う。→ Sebelum mulai konstruksi, lakukan pekerjaan persiapan terlebih dahulu.", _origIndex: 914 },
  { id: 937, category: "sekou", source: "vocab-jac", furi: "こうき", jp: "工期", romaji: "kouki", id_text: "Periode konstruksi / durasi proyek", desc: "例: 工期を守るには工程管理が重要。→ Untuk tepat waktu, manajemen jadwal konstruksi itu krusial.", _origIndex: 921 },
  { id: 941, category: "sekou", source: "vocab-jac", furi: "おしど", jp: "押土", romaji: "oshido", id_text: "Mendorong tanah (bulldozer)", desc: "例: ブルドーザで土砂を押土する。→ Bulldozer dipakai untuk mendorong timbunan tanah.", _origIndex: 925 },
  { id: 942, category: "sekou", source: "vocab-jac", furi: "うんぱん", jp: "運搬", romaji: "unpan", id_text: "Pengangkutan / transport material", desc: "例: ダンプカーで土砂を運搬する。→ Truk dump dipakai untuk mengangkut tanah galian.", _origIndex: 926 },
  { id: 944, category: "sekou", source: "vocab-jac", furi: "くったい", jp: "躯体", romaji: "kutai", id_text: "Struktur utama bangunan", desc: "例: 躯体＝基礎・柱・梁・壁・床。→ Kutai = pondasi + kolom + balok + dinding + lantai.", _origIndex: 928 },
  { id: 945, category: "sekou", source: "vocab-jac", furi: "ないそう", jp: "内装", romaji: "naisou", id_text: "Finishing interior", desc: "例: 躯体工事の後に内装仕上げを行う。→ Setelah struktur selesai, baru pekerjaan finishing interior.", _origIndex: 929 },
  { id: 948, category: "sekou", source: "vocab-jac", furi: "ようじょう", jp: "養生", romaji: "youjou", id_text: "Perawatan beton / curing", desc: "例: コンクリート打設後は養生が必要。→ Setelah pengecoran, beton perlu dirawat agar mengeras sempurna.", _origIndex: 932 },
  { id: 955, category: "sekou", source: "vocab-jac", furi: "いっけん", jp: "一間", romaji: "ikken", id_text: "1 Ken — satuan panjang (≈1.818 m)", desc: "例: 柱の間隔は一間（約1.82m）が基本。→ Jarak antar kolom standar bangunan Jepang = 1 ken.", _origIndex: 939 },
  { id: 966, category: "anzen", source: "vocab-jac", furi: "ついらく", jp: "墜落", romaji: "tsuiraku", id_text: "Jatuh dari ketinggian (orang)", desc: "例: 建設業の三大災害の1位は墜落・転落。→ Jatuh dari ketinggian = penyebab kecelakaan terbesar di konstruksi.", _origIndex: 950 },
  { id: 967, category: "anzen", source: "vocab-jac", furi: "さんそけつぼう", jp: "酸素欠乏", romaji: "sanso ketsubou", id_text: "Kekurangan oksigen", desc: "例: マンホール内は酸素欠乏に注意が必要。→ Di dalam manhole, waspadai kondisi kekurangan oksigen.", _origIndex: 951 },
  { id: 968, category: "anzen", source: "vocab-jac", furi: "どどめ", jp: "土留め", romaji: "dodo me", id_text: "Penahan tanah / soil retaining", desc: "例: 掘削深さ1.5m以上では土留めが必要。→ Galian lebih dari 1.5m wajib pasang penahan tanah.", _origIndex: 952 },
  { id: 969, category: "anzen", source: "vocab-jac", furi: "かんき", jp: "換気", romaji: "kanki", id_text: "Ventilasi / sirkulasi udara", desc: "例: マンホール作業前に換気を行う。→ Sebelum masuk manhole, pastikan ada ventilasi yang cukup.", _origIndex: 953 },
  { id: 970, category: "sekou", source: "vocab-jac", furi: "せこうかんり", jp: "施工管理", romaji: "sekou kanri", id_text: "Manajemen pelaksanaan konstruksi", desc: "例: 施工管理＝品質・工程・原価・安全・環境の管理。→ Construction management = kelola kualitas, jadwal, biaya, K3, lingkungan.", _origIndex: 954 },
  { id: 971, category: "sekou", source: "vocab-jac", furi: "ひんしつ", jp: "品質", romaji: "hinshitsu", id_text: "Kualitas / mutu", desc: "例: 施工管理の4大管理のひとつが品質管理。→ Salah satu dari 4 manajemen konstruksi = quality control.", _origIndex: 955 },
  { id: 972, category: "sekou", source: "vocab-jac", furi: "こうてい", jp: "工程", romaji: "koutei", id_text: "Jadwal / tahapan proses", desc: "例: 工程表で工事の進捗を管理する。→ Gunakan bagan jadwal untuk pantau kemajuan konstruksi.", _origIndex: 956 },
  { id: 973, category: "gaiyou", source: "vocab-jac", furi: "ごあんぜんに", jp: "ご安全に", romaji: "go anzen ni", id_text: "Semoga selamat / stay safe", desc: "例: 工事現場での挨拶は「ご安全に」。→ Sapaan khas di lokasi konstruksi = semoga selamat bekerja.", _origIndex: 957 },
  { id: 975, category: "gaiyou", source: "vocab-jac", furi: "あぶない", jp: "危ない", romaji: "abunai", id_text: "Bahaya! / Awas!", desc: "例: まわりの人が「危ない！」と叫んだらすぐ反応。→ Jika orang sekitar berteriak 'bahaya!', segera bereaksi.", _origIndex: 959 },
  { id: 976, category: "sekou", source: "vocab-core", furi: "しようしょ", jp: "仕様書", romaji: "shiyousho", id_text: "Dokumen spesifikasi teknis", desc: "例: 施工は仕様書に従って行う。→ Pelaksanaan konstruksi harus sesuai spesifikasi teknis.", _origIndex: 960 },
  { id: 977, category: "sekou", source: "vocab-core", furi: "けんちく", jp: "建築", romaji: "kenchiku", id_text: "Bangunan / konstruksi gedung", desc: "例: 建築工事＝住宅・ビルなどの建物を作る工事。→ Pekerjaan membangun rumah, gedung, dll.", _origIndex: 961 },
  { id: 979, category: "sekou", source: "vocab-core", furi: "かいたい", jp: "解体", romaji: "kaitai", id_text: "Pembongkaran / demolition", desc: "例: 解体工事ではアスベストに注意する。→ Dalam pekerjaan bongkar, waspadai material asbes.", _origIndex: 963 },
  { id: 980, category: "sekou", source: "vocab-core", furi: "きそ", jp: "基礎", romaji: "kiso", id_text: "Fondasi / pondasi", desc: "例: 建物の基礎は躯体の一部。→ Fondasi adalah bagian dari struktur utama bangunan.", _origIndex: 964 },
  { id: 984, category: "sekou", source: "vocab-core", furi: "すみだし", jp: "墨出し", romaji: "sumidashi", id_text: "Penarikan garis referensi / layout marking", desc: "例: 壁の位置を墨出しで確認する。→ Posisi dinding ditentukan dengan menarik garis referensi.", _origIndex: 968 },
  { id: 985, category: "sekou", source: "vocab-core", furi: "にげずみ", jp: "逃げ墨", romaji: "nigezumi", id_text: "Garis referensi offset", desc: "例: 仕上げ面から500mm逃げた位置に逃げ墨を引く。→ Garis offset dari permukaan finishing, biasanya 500mm.", _origIndex: 969 },
  { id: 986, category: "sekou", source: "vocab-core", furi: "じずみ", jp: "地墨", romaji: "jizumi", id_text: "Garis lantai / floor marking", desc: "例: 床に直接つける墨を地墨という。→ Garis yang ditarik langsung di lantai = garis lantai.", _origIndex: 970 },
  { id: 993, category: "anzen", source: "vocab-core", furi: "さいがい", jp: "災害", romaji: "saigai", id_text: "Kecelakaan / bencana kerja", desc: "例: 建設業の三大災害＝墜落・機械・温度接触。→ 3 kecelakaan terbesar di konstruksi = jatuh, mesin, suhu ekstrem.", _origIndex: 975 },
  { id: 994, category: "anzen", source: "vocab-core", furi: "きけんよちかつどう", jp: "危険予知活動", romaji: "kiken yochi katsudou", id_text: "Kegiatan prediksi bahaya / KY", desc: "例: 作業前にKYで危険を予測し対策を立てる。→ Sebelum kerja, prediksi bahaya (KY) dan tentukan tindakan pencegahan.", _origIndex: 976 },
  { id: 995, category: "career", source: "vocab-core", furi: "げんばかんとく", jp: "現場監督", romaji: "genba kantoku", id_text: "Pengawas lapangan / site supervisor", desc: "例: 現場監督は品質・安全・工程を管理する。→ Site supervisor mengelola kualitas, K3, dan jadwal di lapangan.", _origIndex: 977 },
  { id: 1010, category: "sekou", source: "vocab-lifeline", furi: "きゃたつ", jp: "脚立", romaji: "kyatatsu", id_text: "Tangga lipat (stepladder)", desc: "Tangga yang bisa berdiri sendiri, dilipat saat tidak digunakan. Untuk pekerjaan di ketinggian sedang.", _origIndex: 989 },
  { id: 1013, category: "sekou", source: "vocab-lifeline", furi: "もんきーれんち", jp: "モンキーレンチ", romaji: "monkii renchi", id_text: "Kunci inggris (adjustable wrench)", desc: "Kunci yang bisa disesuaikan bukaannya untuk berbagai ukuran baut dan mur.", _origIndex: 992 },
  { id: 1017, category: "sekou", source: "vocab-lifeline", furi: "ほーす", jp: "ホース", romaji: "hoosu", id_text: "Selang (hose)", desc: "Pipa fleksibel untuk mengalirkan air atau fluida. Terbuat dari karet atau PVC.", _origIndex: 996 },
  { id: 1024, category: "sekou", source: "vocab-lifeline", furi: "てんじょうない", jp: "天井内", romaji: "tenjou nai", id_text: "Bagian dalam plafon / ceiling space", desc: "Ruang tersembunyi di atas plafon tempat pipa, kabel, dan duct dipasang.", _origIndex: 1003 },
  { id: 1026, category: "sekou", source: "vocab-lifeline", furi: "おくがいろしゅつぶぶん", jp: "屋外露出部分", romaji: "okugai roshutsu bubun", id_text: "Bagian terbuka di luar ruangan", desc: "Area di mana pipa/kabel terekspos langsung ke cuaca luar. Perlu perlindungan anti-UV dan anti-air.", _origIndex: 1005 },
  { id: 1027, category: "sekou", source: "vocab-lifeline", furi: "おくないろしゅつぶぶん", jp: "屋内露出部分", romaji: "okunai roshutsu bubun", id_text: "Bagian terbuka di dalam ruangan", desc: "Area di mana pipa/kabel terlihat langsung di dalam ruangan (tidak tersembunyi di plafon/dinding).", _origIndex: 1006 },
  { id: 1038, category: "sekou", source: "vocab-lifeline", furi: "ばんきんのかこう", jp: "板金の加工", romaji: "bankin no kakou", id_text: "Pengolahan pelat logam", desc: "Proses memotong, menekuk, dan membentuk lembaran logam untuk ducting atau cladding.", _origIndex: 1017 },
  { id: 1039, category: "sekou", source: "vocab-lifeline", furi: "けがき", jp: "ケガキ", romaji: "kegaki", id_text: "Kegaki (marking layout lines)", desc: "Teknik menggaris pada permukaan logam untuk panduan pemotongan/penekukan. Alat: スクライバー.", _origIndex: 1018 },
  { id: 1043, category: "sekou", source: "vocab-lifeline", furi: "わっしゃー", jp: "ワッシャー", romaji: "wasshaa", id_text: "Ring / washer", desc: "Cincin logam tipis yang dipasang di bawah mur/baut untuk mendistribusikan tekanan.", _origIndex: 1022 },
  { id: 1044, category: "sekou", source: "vocab-lifeline", furi: "なっと", jp: "ナット", romaji: "natto", id_text: "Mur (nut)", desc: "Komponen baut berkepala segi enam dengan ulir dalam. Dipasangkan dengan ボルト.", _origIndex: 1023 },
  { id: 1046, category: "sekou", source: "vocab-lifeline", furi: "かんのまいせつこうじ", jp: "管の埋設工事", romaji: "kan no maisetsu kouji", id_text: "Pekerjaan menanam pipa", desc: "Pekerjaan membenamkan pipa ke dalam tanah, termasuk penggalian, pemasangan, dan penimbunan kembali.", _origIndex: 1025 },
  { id: 1048, category: "sekou", source: "vocab-lifeline", furi: "かばー", jp: "カバー", romaji: "kabaa", id_text: "Cover / penutup", desc: "Penutup pelindung untuk pipa, kabel, atau peralatan. Contoh: cable cover, duct cover.", _origIndex: 1027 },
  { id: 1051, category: "sekou", source: "vocab-lifeline", furi: "そうこ", jp: "倉庫", romaji: "souko", id_text: "Gudang", desc: "Tempat menyimpan barang/material. Perlu ventilasi dan penerangan yang memadai.", _origIndex: 1030 },
  { id: 1052, category: "sekou", source: "vocab-lifeline", furi: "きかいしつ", jp: "機械室", romaji: "kikai shitsu", id_text: "Ruang mesin / mechanical room", desc: "Ruang khusus tempat mesin-mesin besar (boiler, chiller, pompa) dipasang.", _origIndex: 1031 },
  { id: 1055, category: "sekou", source: "vocab-lifeline", furi: "ばりとり", jp: "バリ取り", romaji: "bari tori", id_text: "Deburring / hilangkan gerinda", desc: "Proses menghilangkan sisa potongan tajam (gerinda) pada logam setelah dipotong.", _origIndex: 1034 },
  { id: 1056, category: "sekou", source: "vocab-lifeline", furi: "めんをとる", jp: "面を取る", romaji: "men wo toru", id_text: "Chamfering / buat chamfer", desc: "Proses menghaluskan tepi tajam pipa/logam dengan sudut 45° menggunakan cutter atau reamer. Di proyek: dilakukan setelah pemotongan pipa. Mandor:「切断後は必ず面取りをして」(chamfer setelah memotong).", _origIndex: 1035 },
  { id: 1063, category: "anzen", source: "vocab-lifeline", furi: "てんけん", jp: "点検", romaji: "tenken", id_text: "Pengecekan rutin / routine inspection", desc: "Pemeriksaan rutin berkala pada peralatan dan instalasi. Di proyek: wajib dilakukan sebelum mulai bekerja. Mandor:「作業前に点検を忘れないで」(jangan lupa cek rutin sebelum kerja).", _origIndex: 1042 },
  { id: 1223, category: "anzen", source: "vocab-exam", furi: "たんかんあしば", jp: "単管足場", romaji: "tankan ashiba", id_text: "Scaffolding pipa tunggal", desc: "例: 単管足場は鋼管とクランプを組み合わせて組み立てる足場です。→ Scaffolding pipa tunggal dirakit dari pipa baja yang disambung dengan klem. Fleksibel untuk berbagai bentuk bangunan.", _origIndex: 1201 },
  { id: 1224, category: "anzen", source: "vocab-exam", furi: "くさびきんけつしきあしば", jp: "くさび緊結式足場", romaji: "kusabi kinketsushiki ashiba", id_text: "Scaffolding sistem baji / wedge-lock", desc: "例: くさび緊結式足場は、ハンマー一本で組み立て・解体ができる足場です。→ Scaffolding sistem baji dapat dipasang dan dibongkar hanya dengan satu palu. Lebih cepat dari scaffolding pipa tunggal.", _origIndex: 1202 },
  { id: 1225, category: "anzen", source: "vocab-exam", furi: "あんぜんねっと", jp: "安全ネット", romaji: "anzen netto", id_text: "Jaring pengaman (safety net)", desc: "例: 高所作業では、安全ネットを設置して作業員の墜落を防ぎます。→ Saat kerja di ketinggian, safety net dipasang untuk mencegah pekerja jatuh. Wajib dipasang di bawah area kerja yang berisiko.", _origIndex: 1203 },
  { id: 1226, category: "anzen", source: "vocab-exam", furi: "てすり", jp: "手すり", romaji: "tesuri", id_text: "Pegangan tangan / guardrail", desc: "例: 作業床の端には、高さ85cm以上の手すりを設けなければなりません。→ Di tepi platform kerja, guardrail setinggi minimal 85 cm wajib dipasang. Berfungsi mencegah pekerja jatuh dari tepi.", _origIndex: 1204 },
  { id: 1231, category: "anzen", source: "vocab-exam", furi: "りゅうかすいそ", jp: "硫化水素", romaji: "ryuuka suiso", id_text: "Hidrogen sulfida (H₂S)", desc: "例: 硫化水素は腐卵臭のある無色の有毒ガスで、下水道や地下工事で発生しやすいです。→ Hidrogen sulfida adalah gas beracun tak berwarna berbau telur busuk, mudah muncul di pekerjaan saluran dan bawah tanah. Batas aman: di bawah 10 ppm.", _origIndex: 1209 },
  { id: 1233, category: "anzen", source: "vocab-exam", furi: "そうきますく", jp: "送気マスク", romaji: "souki masuku", id_text: "Respirator suplai udara / airline mask", desc: "例: 酸素欠乏や有毒ガスが発生する環境では、送気マスクを着用して作業します。→ Di lingkungan kekurangan oksigen atau bergas beracun, gunakan respirator suplai udara.", _origIndex: 1211 },
  { id: 1235, category: "anzen", source: "vocab-exam", furi: "さぎょうしゅにんしゃ", jp: "作業主任者", romaji: "sagyou shuninsha", id_text: "Pengawas kerja (mandated supervisor)", desc: "例: 足場組立や酸欠危険作業など、特定の危険作業には作業主任者の選任が法律で義務付けられています。→ Untuk pekerjaan berbahaya tertentu seperti pemasangan scaffolding atau ruang oksigen rendah, penunjukan pengawas kerja bersertifikat diwajibkan oleh", _origIndex: 1213 },
  { id: 1238, category: "anzen", source: "vocab-exam", furi: "あんぜんぱとろーる", jp: "安全パトロール", romaji: "anzen patorooru", id_text: "Patroli inspeksi keselamatan", desc: "例: 安全パトロールでは、ヘルメット未着用や足場の異常など危険箇所を点検します。→ Dalam patroli keselamatan, dicek hal-hal seperti helm tidak dipakai atau scaffolding tidak normal. Dilakukan oleh pengawas atau tim K3 secara berkala.", _origIndex: 1216 },
  { id: 1240, category: "anzen", source: "vocab-exam", furi: "ついらくせいしようきぐ", jp: "墜落制止用器具", romaji: "tsuiraku seishi youkigu", id_text: "Alat pencegah jatuh / harness", desc: "例: 高さ2m以上の作業では、墜落制止用器具（フルハーネス型）の使用が義務化されています。→ Penggunaan alat pencegah jatuh tipe full-harness diwajibkan saat bekerja di ketinggian 2 meter atau lebih. Regulasi diperketat sejak 2019.", _origIndex: 1218 },
  { id: 1241, category: "anzen", source: "vocab-exam", furi: "ひらいらっか", jp: "飛来・落下", romaji: "hirai rakka", id_text: "Bahaya benda terbang / jatuh dari atas", desc: "例: 飛来・落下による事故を防ぐため、上部作業中は下の立入を禁止します。→ Untuk mencegah kecelakaan akibat benda terbang atau jatuh, masuk ke area bawah pekerjaan atas dilarang. Helm dan safety shoes wajib di seluruh area konstruksi.", _origIndex: 1219 },
  { id: 1242, category: "anzen", source: "vocab-exam", furi: "ねっちゅうしょう", jp: "熱中症", romaji: "netchuu shou", id_text: "Heat stroke / serangan panas", desc: "例: 夏の屋外作業では、こまめな水分・塩分補給で熱中症を予防します。→ Saat kerja luar ruangan di musim panas, minum air dan suplemen garam secara rutin mencegah heat stroke.", _origIndex: 1220 },
  { id: 1243, category: "anzen", source: "vocab-exam", furi: "ふんじん", jp: "粉じん", romaji: "funjin", id_text: "Debu / partikel berbahaya (dust)", desc: "例: 粉じんが多い現場では、防じんマスクを着用して作業します。→ Di lokasi dengan debu tinggi, gunakan masker anti-debu saat bekerja. Paparan debu jangka panjang dapat menyebabkan pneumokoniosis (penyakit paru akibat debu).", _origIndex: 1221 },
  { id: 1244, category: "anzen", source: "vocab-exam", furi: "りすくあせすめんと", jp: "リスクアセスメント", romaji: "risuku asesuménto", id_text: "Penilaian risiko (risk assessment)", desc: "例: 作業前にリスクアセスメントを行い、危険を特定・評価・対策して記録します。→ Sebelum kerja, lakukan penilaian risiko: identifikasi bahaya, evaluasi tingkat risiko, tetapkan tindakan pencegahan, dan dokumentasikan.", _origIndex: 1222 },
  { id: 1250, category: "sekou", source: "vocab-exam", furi: "しーとぱいる", jp: "シートパイル", romaji: "shiito pairu", id_text: "Sheet pile / turap baja", desc: "例: シートパイルを連続して打ち込み、土砂の崩壊を防ぐ。→ Sheet pile dipancang berurutan untuk mencegah longsornya tanah. Sama dengan 鋼矢板; istilah katakana lebih umum di lapangan.", _origIndex: 1228 },
  { id: 1268, category: "sekou", source: "vocab-exam", furi: "くいうちき", jp: "杭打ち機", romaji: "kui uchi ki", id_text: "Mesin pemancang tiang", desc: "例: 杭打ち機（パイルドライバー）で鋼管杭を所定深さまで打ち込む。→ Mesin pemancang (pile driver) digunakan untuk memancang tiang ke dalam tanah hingga kedalaman yang ditentukan.", _origIndex: 1246 },
  { id: 1278, category: "sekou", source: "vocab-exam", furi: "カーテンウォール", jp: "カーテンウォール", romaji: "kaaten wōru", id_text: "Dinding tirai / curtain wall", desc: "例: 高層ビルのカーテンウォールは建物の荷重を負担しない外壁で、アルミや金属パネルで構成される。→ Curtain wall pada gedung tinggi adalah dinding luar non-struktural yang tidak menanggung beban, biasanya terbuat dari aluminium atau panel logam.", _origIndex: 1256 },
  { id: 1279, category: "sekou", source: "vocab-exam", furi: "サイディング", jp: "サイディング", romaji: "saijingu", id_text: "Siding / pelapis dinding eksterior", desc: "例: 窯業系サイディングは戸建て住宅の外壁仕上げとして広く使われている。→ Siding berbahan keramik (窯業系) adalah penutup dinding luar yang paling umum untuk rumah tinggal di Jepang. Tersedia juga jenis metal dan kayu.", _origIndex: 1257 },
  { id: 1281, category: "sekou", source: "vocab-exam", furi: "プライマー", jp: "プライマー", romaji: "puraimaa", id_text: "Primer / lapisan dasar perekat", desc: "例: シーリング材を充填する前に、目地面にプライマーを塗布して接着力を高める。→ Primer dioleskan ke permukaan celah sebelum aplikasi sealant untuk meningkatkan daya rekat. Tanpa primer, sealant dapat mudah terlepas dari substrat.", _origIndex: 1259 },
  { id: 1298, category: "sekou", source: "vocab-exam", furi: "いんぱくとどらいばー", jp: "インパクトドライバー", romaji: "inpakuto doraibaa", id_text: "Impact driver / bor sekrup bertenaga", desc: "例: インパクトドライバーはビスやボルトを素早く締め付ける電動工具だ。→ Impact driver adalah alat listrik untuk mengencangkan baut dan sekrup dengan cepat. Berbeda dari drill driver biasa karena memberikan pukulan rotasi.", _origIndex: 1276 },
  { id: 1299, category: "sekou", source: "vocab-exam", furi: "ういんち", jp: "ウインチ", romaji: "uinchi", id_text: "Winch / derek penarik bermotor", desc: "例: ウインチで重い資材を引き上げる作業では、ロープの点検が欠かせない。→ Saat menarik material berat dengan winch, pemeriksaan tali/rantai dan kapasitas beban wajib dilakukan sebelum operasi.", _origIndex: 1277 },
  { id: 1302, category: "sekou", source: "vocab-exam", furi: "ゆあつじゃっき", jp: "油圧ジャッキ", romaji: "yuatsu jakki", id_text: "Dongkrak hidrolik / hydraulic jack", desc: "例: 油圧ジャッキで重量物を持ち上げて位置を調整する。→ Dongkrak hidrolik digunakan untuk mengangkat beban berat atau menyesuaikan posisi material konstruksi. Pastikan landasan stabil sebelum mengoperasikan.", _origIndex: 1280 },
  { id: 1312, category: "sekou", source: "vocab-exam", furi: "でんどうどりる", jp: "電動ドリル", romaji: "dendou doriru", id_text: "Bor listrik / electric drill", desc: "例: 電動ドリルは木材・金属・コンクリートへの穴あけに使う汎用工具だ。→ Bor listrik adalah alat serbaguna untuk mengebor kayu, logam, dan beton.", _origIndex: 1290 },
  { id: 1317, category: "sekou", source: "vocab-exam", furi: "ぼーるばん", jp: "ボール盤", romaji: "booruban", id_text: "Mesin bor duduk / drill press", desc: "例: ボール盤は精密な穴あけ作業に使う据え置き型の電動ドリルだ。→ Drill press adalah mesin bor stasioner yang digunakan untuk pengeboran presisi di bengkel atau area persiapan material. Lebih akurat dari electric drill genggam.", _origIndex: 1295 },
  { id: 1323, category: "career", source: "vocab-exam", furi: "ケーワイシート", jp: "KYシート", romaji: "ke wai shi to", id_text: "Lembar prediksi bahaya (KY)", desc: "例: 朝礼でKYシートを記入し、今日の危険ポイントを共有した。→ Saat apel pagi, lembar KY diisi dan titik bahaya hari itu dibagikan ke semua pekerja. Berbeda dengan KYボード — シート adalah formulir tertulis per sesi.", _origIndex: 1301 },
  { id: 1324, category: "career", source: "vocab-exam", furi: "しんきにゅうじょうしゃカード", jp: "新規入場者カード", romaji: "shinki nyuujoushya ka do", id_text: "Kartu pendataan pekerja baru", desc: "例: 新規入場者カードには、氏名・緊急連絡先・保有資格などを記入する。→ Kartu pekerja baru diisi dengan nama, kontak darurat, dan sertifikasi yang dimiliki. Wajib diserahkan sebelum pertama kali masuk lokasi.", _origIndex: 1302 },
  { id: 1334, category: "career", source: "vocab-exam", furi: "せっけいとしょ", jp: "設計図書", romaji: "sekkei tosho", id_text: "Dokumen desain (gambar + spesifikasi)", desc: "例: 設計図書には、設計図・仕様書・現場説明書などが含まれる。→ Dokumen desain mencakup gambar kerja, spesifikasi teknis, dan penjelasan lapangan. Menjadi dasar kontrak dan pelaksanaan.", _origIndex: 1311 },
  { id: 1343, category: "career", source: "vocab-exam", furi: "せこうたいせいだいちょう", jp: "施工体制台帳", romaji: "sekou taisei daichou", id_text: "Buku besar struktur pelaksana proyek", desc: "例: 施工体制台帳には、元請け・下請け・専門業者の情報を記載する。→ Buku besar ini memuat informasi kontraktor utama, sub-kontraktor, dan spesialis. Wajib dibuat pada proyek dengan nilai tertentu ke atas.", _origIndex: 1320 },
  { id: 1346, category: "hourei", source: "vocab-teori", furi: "きょか", jp: "許可", romaji: "kyoka", id_text: "Izin / lisensi usaha konstruksi", desc: "例: 建設業を営むには知事または大臣の許可が必要だ。→ Menjalankan usaha konstruksi wajib mendapat izin dari gubernur atau menteri. 許可なしで工事受注 = 違法（いほう）.", _origIndex: 1323 },
  { id: 1347, category: "hourei", source: "vocab-teori", furi: "うけおいけいやく", jp: "請負契約", romaji: "ukeoi keiyaku", id_text: "Kontrak borongan / construction contract", desc: "例: 建設工事は発注者と元請けの請負契約に基づいて行われる。→ Pekerjaan konstruksi dilakukan berdasarkan kontrak borongan antara pemilik proyek dan kontraktor utama.", _origIndex: 1324 },
  { id: 1348, category: "hourei", source: "vocab-teori", furi: "もとうけ", jp: "元請け", romaji: "motouke", id_text: "Kontraktor utama / prime contractor", desc: "例: 元請けは発注者から直接工事を受注し、下請け全体を管理する。→ Pihak yang menerima proyek langsung dari pemilik; bertanggung jawab atas seluruh sub-kontraktor.", _origIndex: 1325 },
  { id: 1349, category: "hourei", source: "vocab-teori", furi: "したうけ", jp: "下請け", romaji: "shitauke", id_text: "Sub-kontraktor / sub-contractor", desc: "例: 元請けから工事の一部を受注するのが下請け業者だ。→ Pihak yang menerima sebagian pekerjaan dari kontraktor utama. 二次下請け・三次下請けと連鎖する場合もある.", _origIndex: 1326 },
  { id: 1350, category: "hourei", source: "vocab-teori", furi: "ろうどうきじゅんかんとくしょ", jp: "労働基準監督署", romaji: "roudou kijun kantoku sho", id_text: "Kantor Inspeksi Standar Ketenagakerjaan", desc: "例: 労働災害が起きたら、労働基準監督署に速やかに報告する義務がある。→ Jika terjadi kecelakaan kerja, wajib segera melapor ke Kantor Inspeksi. 報告を怠ると労災かくし（犯罪）になる.", _origIndex: 1327 },
  { id: 1351, category: "hourei", source: "vocab-teori", furi: "ゆうきゅうきゅうか", jp: "有給休暇", romaji: "yuukyuu kyuuka", id_text: "Cuti berbayar / paid leave", desc: "例: 6ヶ月継続勤務かつ出勤率80%以上で、10日の有給休暇が付与される。→ Setelah bekerja 6 bulan dengan tingkat kehadiran ≥80%, berhak atas 10 hari cuti berbayar. Hak ini diatur dalam 労働基準法.", _origIndex: 1328 },
  { id: 1352, category: "hourei", source: "vocab-teori", furi: "わりましちんぎん", jp: "割増賃金", romaji: "warimashi chingin", id_text: "Upah premi / overtime premium pay", desc: "例: 時間外労働の割増賃金は、通常の25%増し以上と法律で定められている。→ Upah lembur minimal 1.25× gaji normal sesuai UU Standar Ketenagakerjaan. Lembur >60jam/bulan = 1.5×.", _origIndex: 1329 },
  { id: 1353, category: "hourei", source: "vocab-teori", furi: "ばっそく", jp: "罰則", romaji: "bassoku", id_text: "Sanksi / hukuman pidana pelanggaran UU", desc: "例: 建設業法違反には罰則があり、業許可の取消しや罰金が科せられる。→ Pelanggaran UU Konstruksi dikenai sanksi berupa pencabutan izin usaha atau denda. 罰則を知ることは法令遵守の基本.", _origIndex: 1330 },
  { id: 1356, category: "anzen", source: "vocab-teori", furi: "さんだいさいがい", jp: "三大災害", romaji: "sandai saigai", id_text: "Tiga besar kecelakaan konstruksi", desc: "例: 建設業の三大災害は①墜落・転落②建設機械③崩壊・倒壊だ。→ ①Jatuh dari ketinggian (墜落・転落) = terbanyak, ②Kecelakaan mesin konstruksi, ③Runtuh/kolaps. 安全教育では必ず覚える基礎知識.", _origIndex: 1332 },
  { id: 1357, category: "anzen", source: "vocab-teori", furi: "あんぜんたい", jp: "安全帯", romaji: "anzentai", id_text: "Sabuk/harness keselamatan (generic term)", desc: "例: 高所作業では安全帯（ハーネス型）の着用が義務付けられている。→ Pekerjaan ketinggian wajib memakai safety harness. 2022年以降、フルハーネス型が原則。胴ベルト型は限られた条件のみ.", _origIndex: 1333 },
  { id: 1358, category: "anzen", source: "vocab-teori", furi: "ふるはーねすがた", jp: "フルハーネス型", romaji: "furu haanesugata", id_text: "Full-body harness — standar keselamatan ketinggian", desc: "例: 高さ6.75m以上（建設業は5m以上）ではフルハーネス型安全帯が義務。→ Di ketinggian ≥5m (konstruksi), wajib pakai full harness (bukan sabuk biasa). Mengurangi risiko cedera dalam saat jatuh.", _origIndex: 1334 },
  { id: 1359, category: "anzen", source: "vocab-teori", furi: "たちいりきんし", jp: "立入禁止", romaji: "tachiiri kinshi", id_text: "Dilarang masuk / no-entry zone", desc: "例: 重機の旋回範囲内は立入禁止区域として必ずロープで囲う。→ Area ayunan alat berat wajib dipasang tali dan tanda 'Dilarang Masuk'. 看板や標識の設置義務あり.", _origIndex: 1335 },
  { id: 1360, category: "anzen", source: "vocab-teori", furi: "ほごぐ", jp: "保護具", romaji: "hogogu", id_text: "APD / alat pelindung diri (general term)", desc: "例: 建設現場ではヘルメット・安全靴・安全帯が基本的な保護具だ。→ Helm, sepatu safety, dan harness adalah APD dasar di site konstruksi. 作業内容に応じた適切な保護具の選定が重要.", _origIndex: 1336 },
  { id: 1361, category: "anzen", source: "vocab-teori", furi: "かんでん", jp: "感電", romaji: "kanden", id_text: "Sengatan listrik / electric shock", desc: "例: 電気工事では感電事故を防ぐため、必ず電源を切ってから作業する。→ Dalam pekerjaan listrik, selalu matikan sumber daya sebelum bekerja untuk mencegah sengatan. 感電は最悪の場合死亡事故になる.", _origIndex: 1337 },
  { id: 1364, category: "sekou", source: "vocab-teori", furi: "せこうけいかく", jp: "施工計画", romaji: "sekou keikaku", id_text: "Rencana pelaksanaan konstruksi", desc: "例: 施工計画は工事着工前に作成し、工程・品質・安全の方針を定める。→ Dibuat sebelum pekerjaan dimulai, menetapkan kebijakan jadwal, kualitas, dan keselamatan.", _origIndex: 1338 },
  { id: 1368, category: "hourei", source: "vocab-teori", furi: "はっちゅうしゃ", jp: "発注者", romaji: "hacchuusha", id_text: "Pemilik proyek / project owner / client", desc: "例: 発注者は工事の内容・期間・金額を決め、元請けと請負契約を結ぶ。→ Pihak yang memesan proyek, menentukan isi/durasi/anggaran, dan menandatangani kontrak borongan.", _origIndex: 1340 },
  { id: 1381, category: "gaiyou", source: "vocab-jac", furi: "おはようございます", jp: "おはようございます", romaji: "ohayou gozaimasu", id_text: "Selamat pagi (formal)", desc: "例: 現場に到着したら「おはようございます」と挨拶する。→ Saat tiba di site, ucapkan selamat pagi kepada semua orang. ⚠️ Di konstruksi, sering dipakai sepanjang hari bukan hanya pagi hari.", _origIndex: 1353 },
  { id: 1383, category: "gaiyou", source: "vocab-jac", furi: "ありがとうございます", jp: "ありがとうございます", romaji: "arigatou gozaimasu", id_text: "Terima kasih (formal)", desc: "例: 仕事を手伝ってもらったら「ありがとうございます」。→ Ucapkan setelah dibantu atau menerima sesuatu. Versi kasual ke sesama pekerja: ありがとう (tanpa ございます).", _origIndex: 1355 },
  { id: 1390, category: "gaiyou", source: "vocab-jac", furi: "おさきにしつれいします", jp: "お先に失礼します", romaji: "osaki ni shitsurei shimasu", id_text: "Pamit pulang duluan sebelum orang lain selesai", desc: "例: 仕事が終わって先に帰るとき「お先に失礼します」と言う。→ Ucapkan saat pulang/pergi sebelum rekan kerja lain. Wajib di budaya kerja Jepang — tidak bilang ini dianggap tidak sopan.", _origIndex: 1362 },
  { id: 1392, category: "gaiyou", source: "vocab-jac", furi: "りょうかいしました", jp: "了解しました", romaji: "ryoukai shimashita", id_text: "Siap / roger / mengerti dan akan dilaksanakan", desc: "例: 作業指示を受けて「了解しました、すぐ取りかかります」。→ Lebih aktif dari わかりました — menyiratkan kesiapan untuk bertindak. Di lapangan sering dipersingkat menjadi 了解（りょうかい）. ⚠️ Ke atasan: 承知しました (shouchiشimashita) lebih formal.", _origIndex: 1364 },
  { id: 1396, category: "gaiyou", source: "vocab-jac", furi: "かくにんします", jp: "確認します", romaji: "kakunin shimasu", id_text: "Saya akan memastikan / mengecek", desc: "例: 指示の内容が不明なとき「確認してから報告します」。→ Ungkapkan saat perlu memverifikasi sesuatu sebelum menjawab. 確認 = konfirmasi/verifikasi. Jangan asal bilang OK kalau belum yakin — bilang 確認します!", _origIndex: 1368 },
  { id: 1399, category: "career", source: "vocab-jac", furi: "ほうこく", jp: "報告", romaji: "houkoku", id_text: "Laporan kepada atasan", desc: "例: 作業が完了したら上司に「○○が終わりました」と報告する。→ Setelah menyelesaikan tugas, langsung laporkan ke atasan. ほうれんそうの「ほう」。問題が起きたときも迷わず報告すること。報告なしは信頼を失う。", _origIndex: 1371 },
  { id: 1400, category: "career", source: "vocab-jac", furi: "れんらく", jp: "連絡", romaji: "renraku", id_text: "Komunikasi / pemberitahuan antar tim", desc: "例: 材料が足りなくなったら現場監督に連絡する。→ Jika material habis, segera hubungi supervisor. ほうれんそうの「れん」。こまめな連絡が現場の混乱を防ぐ。情報は抱え込まず共有する。", _origIndex: 1372 },
  { id: 1401, category: "career", source: "vocab-jac", furi: "そうだん", jp: "相談", romaji: "soudan", id_text: "Konsultasi / diskusi dengan atasan/senior", desc: "例: やり方が分からないときは一人で悩まず先輩に相談する。→ Kalau tidak tahu caranya, konsultasikan dengan senior — jangan coba-coba sendiri. ほうれんそうの「そう」。迷ったら必ず相談。", _origIndex: 1373 },
  { id: 1402, category: "career", source: "vocab-jac", furi: "ほうれんそう", jp: "ほう・れん・そう", romaji: "hourenso", id_text: "Lapor–Hubungi–Konsultasi: 3 pilar komunikasi kerja", desc: "例: 建設現場では「ほう・れん・そう」が基本中の基本。ほう=報告、れん=連絡、そう=相談。→ Konsep fundamental komunikasi di tempat kerja Jepang. Tanpa ほうれんそう, koordinasi lapangan gagal. JAC テキストで必出。", _origIndex: 1374 },
  { id: 1403, category: "career", source: "vocab-jac", furi: "しじ", jp: "指示", romaji: "shiji", id_text: "Instruksi / perintah kerja dari atasan", desc: "例: 監督から指示を受けたら、内容をメモして「わかりました」と返事する。→ Saat menerima instruksi, catat isinya dan respons dengan jelas. 指示に従って作業する = bekerja sesuai arahan. 指示なしで勝手に動かない。", _origIndex: 1375 },
  { id: 1408, category: "career", source: "vocab-jac", furi: "とどけで", jp: "届け出", romaji: "todokede", id_text: "Notifikasi / pelaporan resmi (izin/cuti/absen)", desc: "例: 遅刻・欠勤・早退の場合は届け出（とどけで）が必要。→ Terlambat, absen, atau pulang lebih awal semua memerlukan pemberitahuan resmi. 事前の届け出 = izin sebelumnya. 事後報告より事前届けが原則。", _origIndex: 1380 },
  { id: 1412, category: "career", source: "vocab-jac", furi: "きゅうけい", jp: "休憩", romaji: "kyuukei", id_text: "Istirahat / break kerja (hak berdasarkan UU)", desc: "例: 労働基準法で6時間超は45分、8時間超は60分の休憩が義務づけられている。→ UU mewajibkan istirahat: kerja >6 jam = 45 menit, >8 jam = 60 menit. 休憩時間は賃金が発生しない。Tetapi tidak bisa dipotong oleh perusahaan.", _origIndex: 1384 },
  { id: 1413, category: "career", source: "vocab-jac", furi: "ざんぎょう", jp: "残業", romaji: "zangyou", id_text: "Lembur / kerja lebih dari jam normal", desc: "例: 残業は36協定の範囲内で行い、残業代（割増賃金）が支払われる。→ Lembur dilakukan dalam batas 36 perjanjian dan dibayar upah premi. 36協定なしの残業 = 違法。残業時間の上限: 原則45時間/月。", _origIndex: 1385 },
  { id: 1416, category: "hourei", source: "vocab-teori", furi: "とくていぎのう", jp: "特定技能", romaji: "tokutei ginou", id_text: "SSW / Specified Skilled Worker — izin kerja Jepang", desc: "例: 特定技能は2019年創設の在留資格で、人手不足の14分野（建設・製造・介護など）で就労できる。→ Status tinggal baru 2019 untuk bekerja di 14 bidang kekurangan tenaga kerja. 特定技能1号: max 5年, 家族帯同不可 / 2号: 更新可能, 家族帯同可。", _origIndex: 1388 },
  { id: 1417, category: "hourei", source: "vocab-teori", furi: "ざいりゅうかーど", jp: "在留カード", romaji: "zairyuu kaado", id_text: "Kartu izin tinggal / residence card", desc: "例: 在留カードは常に携帯義務。警察・入管に求められたら提示する。住所変更後14日以内に届け出が必要。→ Wajib dibawa setiap saat. Jika diminta polisi/imigrasi, wajib tunjukkan. Masa berlaku tertera di kartu — jangan sampai kedaluwarsa.", _origIndex: 1389 },
  { id: 1418, category: "hourei", source: "vocab-teori", furi: "ざいりゅうしかく", jp: "在留資格", romaji: "zairyuu shikaku", id_text: "Status tinggal / jenis izin untuk tinggal & kerja", desc: "例: 在留資格の種類によって、働ける仕事の範囲が決まる。資格外の仕事をすると不法就労になる。→ Jenis status tinggal menentukan pekerjaan yang boleh dilakukan. 特定技能・技能実習・留学など種類が多い。", _origIndex: 1390 },
  { id: 1419, category: "hourei", source: "vocab-teori", furi: "ざいりゅうきかん", jp: "在留期間", romaji: "zairyuu kikan", id_text: "Masa berlaku izin tinggal", desc: "例: 特定技能1号の在留期間は最長5年。期限が切れる前に更新の手続きが必要。→ Max 5 tahun untuk SSW 1. Wajib proses perpanjangan sebelum kedaluwarsa. 在留期間を過ぎると不法滞在（オーバーステイ）となり強制退去の対象。", _origIndex: 1391 },
  { id: 1421, category: "hourei", source: "vocab-teori", furi: "こうしん", jp: "更新", romaji: "koushin", id_text: "Perpanjangan (visa / izin tinggal / kontrak)", desc: "例: 在留期間の更新は期限の3ヶ月前から申請できる。忘れずに早めに手続きをする。→ Perpanjangan masa tinggal bisa diajukan mulai 3 bulan sebelum kedaluwarsa. 契約の更新, 免許の更新にも使う同じ単語。", _origIndex: 1393 },
  { id: 1422, category: "hourei", source: "vocab-teori", furi: "しゃかいほけん", jp: "社会保険", romaji: "shakai hoken", id_text: "Asuransi sosial — umbrella semua asuransi wajib", desc: "例: 社会保険とは健康保険・厚生年金・雇用保険などの総称で、一定規模の会社では加入義務がある。→ Istilah umum untuk semua asuransi wajib. 保険料は会社と従業員が折半。外国人も加入対象で、一定条件で給付を受けられる。", _origIndex: 1394 },
  { id: 1423, category: "hourei", source: "vocab-teori", furi: "けんこうほけん", jp: "健康保険", romaji: "kenkou hoken", id_text: "Asuransi kesehatan — 30% tanggungan sendiri", desc: "例: 健康保険に加入すると、病院の医療費が原則3割負担になる。→ Dengan asuransi kesehatan, biaya medis jadi 30% tanggungan sendiri (70% ditanggung). 保険証（ほけんしょう）が交付され、病院で提示する。", _origIndex: 1395 },
  { id: 1425, category: "hourei", source: "vocab-teori", furi: "こようほけん", jp: "雇用保険", romaji: "koyou hoken", id_text: "Asuransi ketenagakerjaan (tunjangan pengangguran)", desc: "例: 雇用保険に加入していれば、失業時に失業給付（失業手当）が支給される。→ Jika kehilangan pekerjaan, dapat tunjangan pengangguran dari asuransi ini. 保険料は会社と従業員の両方が負担。育児・介護休業給付もここから。", _origIndex: 1397 },
  { id: 1427, category: "anzen", source: "vocab-teori", furi: "へるめっと", jp: "ヘルメット", romaji: "herumetto", id_text: "Helm keselamatan / hard hat", desc: "例: 建設現場ではヘルメット（保護帽）の着用が義務。あご紐を必ず締める。→ Helm WAJIB di semua site konstruksi — tidak hanya di area kerja aktif. Melindungi kepala dari benda jatuh. JIS T8131規格品を使用。約2年で定期交換。", _origIndex: 1399 },
  { id: 1428, category: "anzen", source: "vocab-teori", furi: "あんぜんぐつ", jp: "安全靴", romaji: "anzengutsu", id_text: "Sepatu safety / steel-toe boots", desc: "例: 安全靴は先芯（つまさき保護）入りで、重量物が落下しても足先を守る。→ Sepatu safety punya pelindung baja di ujung kaki. JIS T8101規格品を選ぶ。現場では必ず着用。スニーカーや普通の靴は不可。", _origIndex: 1400 },
  { id: 1431, category: "anzen", source: "vocab-teori", furi: "ほごめがね", jp: "保護めがね", romaji: "hogo megane", id_text: "Kacamata pelindung / safety goggles", desc: "例: 金属を切断・研磨するとき、飛散する破片から目を守るため保護めがねを着用する。→ Wajib pakai saat menggerinda/memotong logam atau beton. コンタクトレンズ使用者は特に注意 — 粒子が目の中に入ると取り出せない。", _origIndex: 1403 },
  { id: 1433, category: "career", source: "vocab-teori", furi: "けんせつきゃりああっぷしすてむ", jp: "CCUS（建設キャリアアップシステム）", romaji: "kensetsu kyaria appu shisutemu", id_text: "CCUS — kartu IC rekam riwayat karier konstruksi", desc: "例: CCUSカードを現場で毎日打刻すると、就業実績・資格・経験がデジタル管理される。→ Swipe kartu CCUS tiap hari merekam riwayat kerja secara digital. 外国人SSW労働者も登録が推奨（義務化進行中）。レベル評価で処遇改善につながる。", _origIndex: 1404 },
  { id: 1434, category: "career", source: "vocab-teori", furi: "ぎのうれべる", jp: "技能レベル", romaji: "ginou reberu", id_text: "Level keahlian CCUS — level 1 (magang) s.d. 4", desc: "例: CCUSでは技能レベルが4段階で評価：レベル1=見習い → レベル4=職長・班長クラス。→ Level makin tinggi, upah yang wajar makin tinggi dan kesempatan kerja makin luas. SSWは経験を積みながらレベルアップを目指す。", _origIndex: 1405 }
];
